{
  "schema": "brainflow.proc_policy.v1",
  "name": "cli_arg_length_mitigation",
  "applies_to": ["exec", "subprocess", "shell"],
  "rules": {
    "max_cmdline_chars": 7000,
    "prefer_temp_files": true,
    "temp_file_hint": "Use @file or stdin when args would exceed max_cmdline_chars."
  }
}
